require_once dirname(__DIR__) . '/includes/cms.php';$pdo=obtenerConexion();$id=cmsId($_GET['id']??$_POST['id']??0);$preSeccion=cmsId($_GET['seccion_id']??0);$f=['id'=>0,'seccion_id'=>$preSeccion,'titulo'=>'','subtitulo'=>'','descripcion'=>'','imagen'=>'','icono'=>'','enlace'=>'','texto_boton'=>'','activo'=>1,'orden'=>0];
