 if($icono!==''&&!preg_match('/^bi-[a-z0-9-]+$/',$icono))$errores[]='El icono debe ser una clase Bootstrap Icons como bi-star.';if(!cmsUrlValida($enlace))$errores[]='El enlace no es válido.';
 $imagen=$f['imagen'];try{$nueva=cmsSubirImagen('imagen');if($nueva)$imagen=$nueva;}catch(RuntimeException $e){$errores[]=$e->getMessage();}
 if(!$errores){try{$pdo->beginTransaction();$datos=['seccion_id'=>$seccionId,'titulo'=>$titulo,'subtitulo'=>$subtitulo,'descripcion'=>$descripcion,'imagen'=>$imagen,'icono'=>$icono,'enlace'=>$enlace,'texto_boton'=>$textoBoton,'activo'=>$activo,'orden'=>$orden];if($id){$datos['id']=$id;$q=$pdo->prepare('UPDATE elementos_seccion SET seccion_id=:seccion_id,titulo=:titulo,subtitulo=:subtitulo,descripcion=:descripcion,imagen=:imagen,icono=:icono,enlace=:enlace,texto_boton=:texto_boton,activo=:activo,orden=:orden WHERE id=:id');}else{$q=$pdo->prepare('INSERT INTO elementos_seccion(seccion_id,titulo,subtitulo,descripcion,imagen,icono,enlace,texto_boton,activo,orden) VALUES(:seccion_id,:titulo,:subtitulo,:descripcion,:imagen,:icono,:enlace,:texto_boton,:activo,:orden)');}$q->execute($datos);$pdo->commit();if($id&&$imagen!==$f['imagen'])cmsEliminarImagenSiNoSeUsa($f['imagen']);cmsFlash('exito','Elemento guardado correctamente.');header('Location: index.php?seccion_id='.$seccionId);exit;}catch(Throwable $e){if($pdo->inTransaction())$pdo->rollBack();error_log($e->getMessage());$errores[]='No fue posible guardar el elemento.';}}
 $f=array_merge($f,['seccion_id'=>$seccionId,'titulo'=>$titulo,'subtitulo'=>$subtitulo,'descripcion'=>$descripcion,'imagen'=>$imagen,'icono'=>$icono,'enlace'=>$enlace,'texto_boton'=>$textoBoton,'activo'=>$activo,'orden'=>$orden]);
}
cmsCabecera($id?'Editar elemento':'Agregar elemento','elementos/index.php');?>
